    type: "invoice",
    description:
      "Commercial invoices with invoice numbers, bill-to sections, line items, and totals.",
  },
  {
    type: "receipt",
    description:
      "Point-of-sale receipts showing store info, purchased items, and total amounts.",
  },
  {
    type: "contract",
    description:
      "Legal services agreements or contracts with terms and signature blocks.",
  },
];

const RUN_ID = process.env.ZEALT_RUN_ID;

if (!RUN_ID) {
  throw new Error("ZEALT_RUN_ID environment variable is required.");
}

const client = new LlamaCloud();

const uploadFiles = async () => {
  const uploads = await Promise.all(
    SAMPLE_FILES.map(async (filePath) => {
      const file = fs.createReadStream(filePath);
      const created = await client.files.create({ file, purpose: "classify" });
      return { filePath, fileId: created.id };
    })
  );

  return uploads;
};

const run = async () => {
  const uploads = await uploadFiles();
  const fileIds = uploads.map((upload) => upload.fileId);

  const classification = await client.classifier.classify({
    file_ids: fileIds,
    rules: RULES,
    mode: "FAST",
  });

  const lines = [`Run ID: ${RUN_ID}`];

  classification.items.forEach((item, index) => {
    const filePath = uploads[index].filePath;
    const basename = path.basename(filePath);
    lines.push(
      `Classified: ${basename} | Type: ${item.result.type} | Confidence: ${item.result.confidence}`
    );
  });

  fs.writeFileSync(path.join("output.log"), lines.join("\n"));
};

